-- ----------------------------
-- Table structure for drill_event
-- ----------------------------
DROP TABLE IF EXISTS `drill_event`;
CREATE TABLE `drill_event`  (
  `Id` bigint NOT NULL AUTO_INCREMENT,
  `ProjectId` int NOT NULL,
  `Stage` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'scene/report/response/review/end/recovery',
  `EventType` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'system/teacher/student',
  `Title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `Content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `OccurAt` datetime NULL DEFAULT NULL COMMENT '事件发生时间（可编辑）',
  `UserId` int NULL DEFAULT NULL,
  `UserName` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `RoleName` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `CreateDate` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`Id`) USING BTREE,
  INDEX `IX_drill_event_ProjectId`(`ProjectId` ASC) USING BTREE,
  INDEX `IX_drill_event_ProjectId_OccurAt`(`ProjectId` ASC, `OccurAt` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 312 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of drill_event
-- ----------------------------

-- ----------------------------
-- Table structure for drill_flow_assignment
-- ----------------------------
DROP TABLE IF EXISTS `drill_flow_assignment`;
CREATE TABLE `drill_flow_assignment`  (
  `Id` bigint NOT NULL AUTO_INCREMENT,
  `ProjectId` int NULL DEFAULT NULL COMMENT 'NULL 表示全局模板，非空表示项目覆盖',
  `NodeCode` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `RoleName` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `TaskTitle` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `TaskDetail` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `StepsJson` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '步骤 JSON',
  `SubmitType` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'text/image/voice/checklist',
  `EvidenceRequired` int NOT NULL DEFAULT 0,
  `OrderNo` int NOT NULL DEFAULT 0,
  `Enable` int NOT NULL DEFAULT 1,
  `CreateDate` datetime NULL DEFAULT NULL,
  `ModifyDate` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`Id`) USING BTREE,
  INDEX `IX_drill_flow_assignment_ProjectId`(`ProjectId` ASC) USING BTREE,
  INDEX `IX_drill_flow_assignment_NodeCode`(`NodeCode` ASC) USING BTREE,
  INDEX `IX_drill_flow_assignment_RoleName`(`RoleName` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 20 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of drill_flow_assignment
-- ----------------------------

-- ----------------------------
-- Table structure for drill_flow_node
-- ----------------------------
DROP TABLE IF EXISTS `drill_flow_node`;
CREATE TABLE `drill_flow_node`  (
  `Id` bigint NOT NULL AUTO_INCREMENT,
  `ProjectId` int NULL DEFAULT NULL COMMENT 'NULL 表示全局模板，非空表示项目覆盖',
  `NodeCode` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '节点编码',
  `NodeName` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '节点名称',
  `Stage` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'scene/discussion/report/response/review/end',
  `OrderNo` int NOT NULL DEFAULT 0,
  `NextNodeCode` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `Description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `ResourceId` bigint NULL DEFAULT NULL COMMENT '节点绑定的视频资源ID',
  `VideoStartSeconds` int NULL DEFAULT NULL COMMENT '节点对应视频起播秒数',
  `VideoEndSeconds` int NULL DEFAULT NULL COMMENT '节点对应视频结束秒数',
  `Enable` int NOT NULL DEFAULT 1,
  `CreateDate` datetime NULL DEFAULT NULL,
  `ModifyDate` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`Id`) USING BTREE,
  INDEX `IX_drill_flow_node_ProjectId`(`ProjectId` ASC) USING BTREE,
  INDEX `IX_drill_flow_node_NodeCode`(`NodeCode` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 104 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of drill_flow_node
-- ----------------------------

-- ----------------------------
-- Table structure for drill_message
-- ----------------------------
DROP TABLE IF EXISTS `drill_message`;
CREATE TABLE `drill_message`  (
  `Id` bigint NOT NULL AUTO_INCREMENT,
  `ProjectId` int NOT NULL,
  `Channel` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'discussion/speech',
  `ParentMessageId` bigint NULL DEFAULT NULL COMMENT '点评绑定的上级消息ID',
  `NodeCode` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '消息所属节点编码',
  `Content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `UserId` int NULL DEFAULT NULL,
  `UserName` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `RoleName` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `CreateDate` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`Id`) USING BTREE,
  INDEX `IX_drill_message_ProjectId`(`ProjectId` ASC) USING BTREE,
  INDEX `IX_drill_message_ProjectId_Channel`(`ProjectId` ASC, `Channel` ASC) USING BTREE,
  INDEX `IX_drill_message_ParentMessageId`(`ParentMessageId` ASC) USING BTREE,
  INDEX `IX_drill_message_Project_Channel_Node`(`ProjectId` ASC, `Channel` ASC, `NodeCode` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 57 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of drill_message
-- ----------------------------

-- ----------------------------
-- Table structure for drill_project_member
-- ----------------------------
DROP TABLE IF EXISTS `drill_project_member`;
CREATE TABLE `drill_project_member`  (
  `Id` bigint NOT NULL AUTO_INCREMENT,
  `ProjectId` int NOT NULL COMMENT '项目ID',
  `UserId` int NULL DEFAULT NULL COMMENT '关联sys_user，审核通过后写入',
  `UserName` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '系统用户名',
  `RoleName` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '角色：总指挥、110、政府办公室、群众、观察者等',
  `UserTrueName` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '真实姓名',
  `Org` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '所在单位',
  `JobTitle` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '职务',
  `Contact` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '联系方式',
  `Photo` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '照片URL',
  `AuditStatus` int NOT NULL DEFAULT 0 COMMENT '0待审核 1通过 2拒绝',
  `SignedAt` datetime NULL DEFAULT NULL COMMENT '签到时间',
  `CreateDate` datetime NULL DEFAULT NULL,
  `ModifyDate` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`Id`) USING BTREE,
  UNIQUE INDEX `UX_drill_project_member_Project_User`(`ProjectId` ASC, `UserName` ASC) USING BTREE,
  INDEX `IX_drill_project_member_ProjectId`(`ProjectId` ASC) USING BTREE,
  INDEX `IX_drill_project_member_UserId`(`UserId` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '演练项目成员/学员' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of drill_project_member
-- ----------------------------

-- ----------------------------
-- Table structure for drill_project_state
-- ----------------------------
DROP TABLE IF EXISTS `drill_project_state`;
CREATE TABLE `drill_project_state`  (
  `Id` bigint NOT NULL AUTO_INCREMENT,
  `ProjectId` int NOT NULL,
  `Status` int NOT NULL DEFAULT 0 COMMENT '0未开始 1运行中 2暂停 3已结束',
  `CurrentStage` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'scene/report/response/review/end/recovery',
  `CurrentNodeCode` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '当前流程节点编码',
  `StartedAt` datetime NULL DEFAULT NULL,
  `PausedAt` datetime NULL DEFAULT NULL,
  `EndedAt` datetime NULL DEFAULT NULL,
  `SettingsJson` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `CreateDate` datetime NULL DEFAULT NULL,
  `CreateID` int NULL DEFAULT NULL,
  `Creator` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `ModifyDate` datetime NULL DEFAULT NULL,
  `ModifyID` int NULL DEFAULT NULL,
  `Modifier` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `ElapsedSeconds` int NOT NULL DEFAULT 0 COMMENT '累计已运行秒数',
  `LastResumedAt` datetime NULL DEFAULT NULL COMMENT '最近一次进入运行态时间',
  PRIMARY KEY (`Id`) USING BTREE,
  UNIQUE INDEX `UX_drill_project_state_ProjectId`(`ProjectId` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 40 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

