-- Table structure for drill_recovery_item
-- ----------------------------
DROP TABLE IF EXISTS `drill_recovery_item`;
CREATE TABLE `drill_recovery_item`  (
  `Id` bigint NOT NULL AUTO_INCREMENT,
  `ProjectId` int NOT NULL,
  `Category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'cleanup/order/claim/investigation',
  `Title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
