-- ----------------------------
-- Triggers structure for table drill_project_member
-- ----------------------------
DROP TRIGGER IF EXISTS `trg_drill_member_before_insert_userid`;
delimiter ;;
CREATE TRIGGER `trg_drill_member_before_insert_userid` BEFORE INSERT ON `drill_project_member` FOR EACH ROW BEGIN
  IF IFNULL(@sync_usertruename_guard, 0) = 0
     AND NEW.`UserId` IS NULL
     AND NEW.`UserName` IS NOT NULL
     AND NEW.`UserName` <> '' THEN
    SET NEW.`UserId` = (
      SELECT u.`User_Id`
      FROM `sys_user` u
      WHERE u.`UserName` COLLATE utf8mb4_general_ci = NEW.`UserName` COLLATE utf8mb4_general_ci
      LIMIT 1
    );
  END IF;
END
;;
delimiter ;

-- ----------------------------
-- Triggers structure for table drill_project_member
-- ----------------------------
DROP TRIGGER IF EXISTS `trg_drill_member_insert_usertruename_to_user`;
delimiter ;;
CREATE TRIGGER `trg_drill_member_insert_usertruename_to_user` AFTER INSERT ON `drill_project_member` FOR EACH ROW BEGIN
  IF IFNULL(@sync_usertruename_guard, 0) = 0
     AND NEW.`UserTrueName` IS NOT NULL
     AND NEW.`UserTrueName` <> '' THEN
    SET @sync_usertruename_guard = 1;
    IF NEW.`UserId` IS NOT NULL THEN
      UPDATE `sys_user`
      SET `UserTrueName` = NEW.`UserTrueName`,
          `ModifyDate` = NOW()
      WHERE `User_Id` = NEW.`UserId`
        AND NOT (IFNULL(`UserTrueName`, '') COLLATE utf8mb4_general_ci <=> IFNULL(NEW.`UserTrueName`, '') COLLATE utf8mb4_general_ci);
    ELSEIF NEW.`UserName` IS NOT NULL AND NEW.`UserName` <> '' THEN
      UPDATE `sys_user`
      SET `UserTrueName` = NEW.`UserTrueName`,
          `ModifyDate` = NOW()
      WHERE `UserName` COLLATE utf8mb4_general_ci = NEW.`UserName` COLLATE utf8mb4_general_ci
        AND NOT (IFNULL(`UserTrueName`, '') COLLATE utf8mb4_general_ci <=> IFNULL(NEW.`UserTrueName`, '') COLLATE utf8mb4_general_ci);
    END IF;
    SET @sync_usertruename_guard = 0;
  END IF;
END
;;
delimiter ;

-- ----------------------------
-- Triggers structure for table drill_project_member
-- ----------------------------
DROP TRIGGER IF EXISTS `trg_drill_member_usertruename_to_user`;
delimiter ;;
CREATE TRIGGER `trg_drill_member_usertruename_to_user` AFTER UPDATE ON `drill_project_member` FOR EACH ROW BEGIN
  IF IFNULL(@sync_usertruename_guard, 0) = 0
     AND NOT (IFNULL(OLD.`UserTrueName`, '') <=> IFNULL(NEW.`UserTrueName`, '')) THEN
    SET @sync_usertruename_guard = 1;
    IF NEW.`UserId` IS NOT NULL THEN
      UPDATE `sys_user`
      SET `UserTrueName` = NEW.`UserTrueName`,
          `ModifyDate` = NOW()
      WHERE `User_Id` = NEW.`UserId`
        AND NOT (IFNULL(`UserTrueName`, '') COLLATE utf8mb4_general_ci <=> IFNULL(NEW.`UserTrueName`, '') COLLATE utf8mb4_general_ci);
    ELSEIF NEW.`UserName` IS NOT NULL AND NEW.`UserName` <> '' THEN
      UPDATE `sys_user`
      SET `UserTrueName` = NEW.`UserTrueName`,
          `ModifyDate` = NOW()
      WHERE `UserName` COLLATE utf8mb4_general_ci = NEW.`UserName` COLLATE utf8mb4_general_ci
        AND NOT (IFNULL(`UserTrueName`, '') COLLATE utf8mb4_general_ci <=> IFNULL(NEW.`UserTrueName`, '') COLLATE utf8mb4_general_ci);
    END IF;
    SET @sync_usertruename_guard = 0;
  END IF;
END
;;
delimiter ;

-- ----------------------------
-- Triggers structure for table sys_user
-- ----------------------------
DROP TRIGGER IF EXISTS `trg_sys_user_usertruename_to_member`;
delimiter ;;
CREATE TRIGGER `trg_sys_user_usertruename_to_member` AFTER UPDATE ON `sys_user` FOR EACH ROW BEGIN
  IF IFNULL(@sync_usertruename_guard, 0) = 0
     AND NOT (IFNULL(OLD.`UserTrueName`, '') <=> IFNULL(NEW.`UserTrueName`, '')) THEN
    SET @sync_usertruename_guard = 1;
    UPDATE `drill_project_member`
    SET `UserTrueName` = NEW.`UserTrueName`,
        `UserId` = NEW.`User_Id`,
        `ModifyDate` = NOW()
    WHERE (`UserId` = NEW.`User_Id`
           OR (`UserName` COLLATE utf8mb4_general_ci = NEW.`UserName` COLLATE utf8mb4_general_ci))
      AND NOT (IFNULL(`UserTrueName`, '') COLLATE utf8mb4_general_ci <=> IFNULL(NEW.`UserTrueName`, '') COLLATE utf8mb4_general_ci);
    SET @sync_usertruename_guard = 0;
  END IF;
END
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
